import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { recipeAPI, categoryAPI } from "../utils/api";
import "../styles/Home.css";

const Home = () => {
  const [featuredRecipes, setFeaturedRecipes] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchHomeData();
  }, []);

  const fetchHomeData = async () => {
    try {
      const [recipesRes, categoriesRes] = await Promise.all([
        recipeAPI.getAll({ limit: 6 }),
        categoryAPI.getAll(),
      ]);

      setFeaturedRecipes(recipesRes.data.recipes || recipesRes.data.data || []);
      setCategories(categoriesRes.data || []);
    } catch (error) {
      console.error("Error fetching home data:", error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="loading">Loading delicious recipes...</div>;
  }

  return (
    <div className="home">
      <section className="hero">
        <div className="hero-content">
          <h1>Welcome to RecipeBook</h1>
          <p>
            Discover amazing recipes from around the world. Cook like a
            professional chef with our easy-to-follow recipes.
          </p>
          <div className="hero-buttons">
            <Link to="/recipes" className="btn btn-primary">
              Explore Recipes
            </Link>
            <Link to="/add-recipe" className="btn btn-secondary">
              Share Your Recipe
            </Link>
          </div>
        </div>
      </section>

      <section className="categories-section">
        <div className="container">
          <h2>Recipe Categories</h2>
          <p className="section-subtitle">Browse recipes by category</p>
          <div className="categories-grid">
            {categories.map((category) => (
              <Link
                key={category.name || category._id}
                to={`/categories/${category.name}`}
                className="category-card"
              >
                <div className="category-icon">
                  {getCategoryIcon(category.name)}
                </div>
                <h3>
                  {category.name
                    ? category.name.charAt(0).toUpperCase() +
                      category.name.slice(1)
                    : "Category"}
                </h3>
                <p>{category.recipeCount || 0} recipes</p>
              </Link>
            ))}
          </div>
        </div>
      </section>

      <section className="featured-recipes">
        <div className="container">
          <h2>Featured Recipes</h2>
          <p className="section-subtitle">Try these popular recipes</p>
          <div className="recipes-grid">
            {featuredRecipes.map((recipe) => (
              <RecipeCard key={recipe._id} recipe={recipe} />
            ))}
          </div>
          {featuredRecipes.length === 0 && (
            <div className="no-recipes">
              <p>No recipes yet. Be the first to add one!</p>
              <Link to="/add-recipe" className="btn btn-primary">
                Add First Recipe
              </Link>
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

const RecipeCard = ({ recipe }) => (
  <div className="recipe-card">
    <div className="recipe-image">
      <img
        src={
          recipe.image
            ? `http://localhost:5000/uploads/${recipe.image}`
            : "https://via.placeholder.com/300x200/667eea/ffffff?text=No+Image"
        }
        alt={recipe.title}
        onError={(e) => {
          e.target.src =
            "https://via.placeholder.com/300x200/667eea/ffffff?text=No+Image";
        }}
      />
      <div className="recipe-overlay">
        <span className="category-tag">{recipe.category}</span>
      </div>
    </div>
    <div className="recipe-info">
      <h3>{recipe.title}</h3>
      <p className="recipe-description">
        {recipe.description.substring(0, 100)}...
      </p>
      <div className="recipe-meta">
        <span>⏱️ {recipe.prepTime + recipe.cookTime} mins</span>
        <span>👥 {recipe.servings} servings</span>
        <span className={`difficulty ${recipe.difficulty}`}>
          {recipe.difficulty}
        </span>
      </div>
      <div className="recipe-actions">
        <Link to={`/recipes/${recipe._id}`} className="btn btn-primary">
          View Recipe
        </Link>
      </div>
    </div>
  </div>
);

const getCategoryIcon = (category) => {
  const icons = {
    indian: "🍛",
    chinese: "🥡",
    italian: "🍝",
    mexican: "🌮",
    thai: "🍜",
    american: "🍔",
    mediterranean: "🥗",
    japanese: "🍣",
    french: "🥐",
    other: "🍽️",
  };
  return icons[category] || "🍽️";
};

export default Home;
